importScripts("https://cdn.jsdelivr.net/pyodide/v0.29.3/full/pyodide.js");

function sendPatch(patch, buffers, msg_id) {
  self.postMessage({
    type: 'patch',
    patch: patch,
    buffers: buffers
  })
}

async function startApplication() {
  console.log("Loading pyodide...");
  self.postMessage({type: 'status', msg: 'Loading pyodide'})
  self.pyodide = await loadPyodide();
  self.pyodide.globals.set("sendPatch", sendPatch);
  console.log("Loaded pyodide!");
  const data_archives = [];
  for (const archive of data_archives) {
    let zipResponse = await fetch(archive);
    let zipBinary = await zipResponse.arrayBuffer();
    self.postMessage({type: 'status', msg: `Unpacking ${archive}`})
    self.pyodide.unpackArchive(zipBinary, "zip");
  }
  await self.pyodide.loadPackage("micropip");
  self.postMessage({type: 'status', msg: `Installing environment`})
  try {
    await self.pyodide.runPythonAsync(`
      import micropip
      await micropip.install(['https://cdn.holoviz.org/panel/wheels/bokeh-3.9.0-py3-none-any.whl', 'https://cdn.holoviz.org/panel/1.9.2/dist/wheels/panel-1.9.2-py3-none-any.whl', 'pyodide-http', 'numpy', 'pandas', 'param']);
    `);
  } catch(e) {
    console.log(e)
    self.postMessage({
      type: 'status',
      msg: `Error while installing packages`
    });
  }
  console.log("Environment loaded!");
  self.postMessage({type: 'status', msg: 'Executing code'})
  try {
    const [docs_json, render_items, root_ids] = await self.pyodide.runPythonAsync(`\nimport asyncio\n\nfrom panel.io.pyodide import init_doc, write_doc\n\ninit_doc()\n\n# AUTO-GENERATED by make_deploy_app.py \u2014 do not edit. Edit the modules.\n\n# ===== inlined from superposition.py =====\n\n"""Client-side superposition engine (library C) + coherence rule.\n\nPure numpy. Implements EXACTLY the math in CONTRACT.md section\n"THE SUPERPOSITION + COHERENCE MATH". No flopy/pyemu, no MF6.\n\nSign conventions (from contract):\n  - Abstraction rates are NEGATIVE (m3/d).\n  - Unit responses (dd_grid, sfr, bh) are stored POSITIVE = effect of pumping\n    at U = unit_rate_m3d (= -300 m3/d).\n  - Scale factor for a well = q / U  (dimensionless).\n  - Existing wells superpose the DELTA (q_w - q0_w)/U  (baseline already has\n    calibrated pumping). Preset wells superpose on_pw * (q_pw / U).\n  - DD > 0 means head lowered / flow depleted.\n\nMap coherence rule:\n  map_central[r][c] = baseline_heads.mean[rl][sp][r][c] - DD[r][c]\n"""\n\nimport numpy as np\n\n# Inactive-domain sentinel written by the offline pipeline (json_io._rg).\n# Must be masked to NaN at load so it never enters superposition arithmetic\n# (-9999 - scale*-9999 would otherwise produce garbage at inactive cells) and\n# so Bokeh renders those cells transparent. Re-stamped to NODATA on ESRI export.\nNODATA = -9999.0\n\n\ndef _mask_nodata(a: np.ndarray) -> np.ndarray:\n    """Return float copy with NODATA sentinel cells set to NaN."""\n    a = np.asarray(a, dtype=float)\n    a[a <= -9990.0] = np.nan\n    return a\n\n\nclass Superposer:\n    """Holds the pre-computed kernels and baseline arrays as numpy, applies math."""\n\n    def __init__(self, meta, grid, baseline_heads, baseflow, hydrographs, unit_response):\n        self.U = float(meta["unit_rate_m3d"])\n        self.nrow = int(meta["grid"]["nrow"])\n        self.ncol = int(meta["grid"]["ncol"])\n        self.nper = int(meta["stress_periods"]["nper"])\n        self.nrlev = int(meta["recharge_levels"]["nrlev"])\n\n        self.existing_ids = [w["id"] for w in grid["wells_existing"]]\n        self.preset_ids = [p["id"] for p in grid["wells_preset"]]\n        self.base_rate = {w["id"]: float(w["base_rate_m3d"]) for w in grid["wells_existing"]}\n        self.well_cell = {\n            **{w["id"]: (w["row"], w["col"]) for w in grid["wells_existing"]},\n            **{p["id"]: (p["row"], p["col"]) for p in grid["wells_preset"]},\n        }\n\n        # baseline heads: [rl][sp][r][c] \u2014 NODATA sentinel -> NaN\n        self.bh_mean = _mask_nodata(baseline_heads["mean"])\n        self.bh_p10 = _mask_nodata(baseline_heads["p10"])\n        self.bh_p90 = _mask_nodata(baseline_heads["p90"])\n        self.bh_std = _mask_nodata(baseline_heads["std"])\n\n        # baseflow series: [rl][sp]\n        self.bf = baseflow\n        self.primary_series = baseflow.get("primary_series", "GAGE-1")\n        self.threshold = float(baseflow["threshold_m3d"])\n\n        # hydrographs\n        self.hydro = hydrographs\n\n        # unit response kernels -> numpy\n        ur = unit_response["wells"]\n        self.dd_grid = {}   # wid -> [sp][r][c]\n        self.sfr = {}       # wid -> {gage -> [sp]}\n        self.bh_resp = {}   # wid -> {bid -> [sp]}\n        for wid, w in ur.items():\n            self.dd_grid[wid] = _mask_nodata(w["dd_grid"])\n            self.sfr[wid] = {g: np.asarray(v, dtype=float) for g, v in w["sfr"].items()}\n            self.bh_resp[wid] = {b: np.asarray(v, dtype=float) for b, v in w["bh"].items()}\n\n        # Constant inactive-domain mask (idomain is fixed across rl/sp): any cell\n        # that is NaN in the baseline heads. Used to blank the drawdown-delta view,\n        # whose array starts from zeros (no NaN) when no wells are active.\n        self.inactive2d = np.any(np.isnan(self.bh_mean), axis=(0, 1))\n\n    # --- scale factors ------------------------------------------------------\n    def _scales(self, existing_rates: dict, preset_rates: dict, preset_on: dict):\n        """Return {wid: scale} for every well that contributes (nonzero)."""\n        scales = {}\n        for wid in self.existing_ids:\n            q = existing_rates.get(wid, self.base_rate[wid])\n            scale = (q - self.base_rate[wid]) / self.U\n            if scale != 0.0:\n                scales[wid] = scale\n        for pid in self.preset_ids:\n            if preset_on.get(pid, False):\n                q = preset_rates.get(pid, 0.0)\n                scale = q / self.U\n                if scale != 0.0:\n                    scales[pid] = scale\n        return scales\n\n    # --- drawdown grid for a single stress period ---------------------------\n    def drawdown_grid(self, sp, existing_rates, preset_rates, preset_on):\n        """Superposed DD[r][c] (POSITIVE = head lowered) at stress period sp."""\n        dd = np.zeros((self.nrow, self.ncol), dtype=float)\n        for wid, scale in self._scales(existing_rates, preset_rates, preset_on).items():\n            dd += scale * self.dd_grid[wid][sp]\n        return dd\n\n    def map_central(self, rl, sp, existing_rates, preset_rates, preset_on):\n        """Coherence rule: baseline mean head MINUS superposed drawdown."""\n        dd = self.drawdown_grid(sp, existing_rates, preset_rates, preset_on)\n        return self.bh_mean[rl, sp] - dd\n\n    def map_delta(self, rl, sp, existing_rates, preset_rates, preset_on):\n        """Drawdown-vs-baseline: negative = head lowered (== -DD).\n        Inactive cells blanked to NaN (the zeros-init array carries no NaN)."""\n        delta = -self.drawdown_grid(sp, existing_rates, preset_rates, preset_on)\n        delta[self.inactive2d] = np.nan\n        return delta\n\n    # --- baseflow series ----------------------------------------------------\n    def baseflow_series(self, rl, existing_rates, preset_rates, preset_on, series=None):\n        """Return (mean_central, p10, p90) length-nper arrays for a gage series."""\n        name = series or self.primary_series\n        s = self.bf["series"][name]\n        mean = np.asarray(s["mean"][rl], dtype=float).copy()\n        p10 = np.asarray(s["p10"][rl], dtype=float)\n        p90 = np.asarray(s["p90"][rl], dtype=float)\n        depletion = np.zeros(self.nper, dtype=float)\n        for wid, scale in self._scales(existing_rates, preset_rates, preset_on).items():\n            if name in self.sfr[wid]:\n                depletion += scale * self.sfr[wid][name]\n        central = mean - depletion  # depletion>0 reduces baseflow\n        # bands shift with the central deviation so the band tracks the line\n        shift = central - mean\n        # Physical floor: baseflow at a gaining gage cannot go negative. Linear\n        # superposition can overshoot below zero at large abstraction (the\n        # caveated linearity limit) \u2014 clamp at 0 so the headline view stays\n        # physically readable (the threshold-breach story is unaffected).\n        return (np.maximum(central, 0.0),\n                np.maximum(p10 + shift, 0.0),\n                np.maximum(p90 + shift, 0.0))\n\n    # --- borehole hydrograph ------------------------------------------------\n    def hydrograph_series(self, rl, bid, existing_rates, preset_rates, preset_on):\n        """Return (mean_central, p10, p90) length-nper for borehole bid."""\n        b = self.hydro["boreholes"][bid]\n        mean = np.asarray(b["mean"][rl], dtype=float).copy()\n        p10 = np.asarray(b["p10"][rl], dtype=float)\n        p90 = np.asarray(b["p90"][rl], dtype=float)\n        dd_at_b = np.zeros(self.nper, dtype=float)\n        for wid, scale in self._scales(existing_rates, preset_rates, preset_on).items():\n            if bid in self.bh_resp[wid]:\n                dd_at_b += scale * self.bh_resp[wid][bid]\n        central = mean - dd_at_b\n        shift = central - mean\n        return central, p10 + shift, p90 + shift\n\n# ===== inlined from data_loader.py =====\n\n"""Single data-access seam for the runtime app.\n\nSwapping mock data for the real offline-produced data is a ONE-LINE change:\nset \`\`USE_MOCK = False\`\` below. Everything else in the app reads through\n\`\`load_all()\`\` and never knows the difference.\n\nRUNTIME IMPORT RULE: this module imports ONLY \`\`json\`\` and (lazily, inside a\ntry/except) \`\`pyodide.http\`\` and the dev-only \`\`mock_data\`\`. It never imports\nflopy/pyemu/MF6. \`\`mock_data\`\` is imported only when \`\`USE_MOCK\`\` is True AND we\nare running under plain CPython for development; it is never reached in the\nbrowser when \`\`USE_MOCK\`\` is False.\n\nData resolution order:\n  - USE_MOCK True  : read the seven JSON files from \`\`app/mock_data_files/\`\`,\n                     generating them on the fly if absent (dev convenience).\n  - USE_MOCK False : fetch \`\`data/<name>.json\`\` via \`\`pyodide.http.open_url\`\`\n                     (browser), falling back to a local \`\`../docs/data/\`\` read\n                     when previewing under plain CPython.\n"""\n\nimport json\nimport os\n\n# === THE ONE-LINE SEAM ======================================================\n# False (default): real data \u2014 browser fetches docs/data/*.json; local \`panel\n#   serve\` falls back to reading ../docs/data, so dev MATCHES the live site.\n# True: CONTRACT-shaped synthetic mock (smooth analytic field) for offline dev\n#   when the real docs/data/*.json have not been generated yet.\nUSE_MOCK = False\n# ============================================================================\n\nFILES = [\n    "meta.json",\n    "grid.json",\n    "baseline_heads.json",\n    "baseflow.json",\n    "hydrographs.json",\n    "budget.json",\n    "unit_response.json",\n]\n\n_HERE = '.'  # bundle: __file__ undefined in pyodide; mock dir unused\n_MOCK_DIR = os.path.join(_HERE, "mock_data_files")\n# When deployed, data lives next to app.html under docs/data/.\n_REAL_LOCAL_DIR = '/Users/ruihugman/GitHub/uk_mf6_tender/dashboard/docs/data'\n\n\ndef _read_local(path: str):\n    with open(path) as f:\n        return json.load(f)\n\n\ndef _fetch_browser(name: str):\n    """Browser path: synchronous fetch via pyodide (worker mode). Relative URL."""\n    from pyodide.http import open_url  # noqa: WPS433 (lazy, pyodide-only)\n    return json.load(open_url(f"data/{name}"))\n\n\ndef _load_mock():\n    """Read mock files, generating them first if the directory is empty/missing."""\n    need_gen = not os.path.isdir(_MOCK_DIR) or not all(\n        os.path.exists(os.path.join(_MOCK_DIR, n)) for n in FILES\n    )\n    if need_gen:\n        # Dev-only: build the mock files now. mock_data is never shipped to WASM.\n        mock_data.write_all(_MOCK_DIR)\n    return {n: _read_local(os.path.join(_MOCK_DIR, n)) for n in FILES}\n\n\ndef _load_real():\n    """Real path. Try the browser fetch; fall back to a local preview read."""\n    try:\n        return {n: _fetch_browser(n) for n in FILES}\n    except Exception:\n        return {n: _read_local(os.path.join(_REAL_LOCAL_DIR, n)) for n in FILES}\n\n\ndef load_all():\n    """Return a dict keyed by contract filename -> parsed JSON object.\n\n    Keys: 'meta.json', 'grid.json', 'baseline_heads.json', 'baseflow.json',\n          'hydrographs.json', 'budget.json', 'unit_response.json'.\n    """\n    if USE_MOCK:\n        return _load_mock()\n    return _load_real()\n\n\ndef load_model_structure():\n    """Optional Model-Explorer payload -> parsed dict, or None if absent.\n\n    NOT part of the seven-file CONTRACT: it is loaded separately so a missing\n    \`\`model_structure.json\`\` degrades the Explorer tab gracefully instead of\n    breaking the whole app. Same resolution order as the real data: browser\n    fetch of \`\`data/model_structure.json\`\` first, then a local preview read.\n    """\n    try:\n        return _fetch_browser("model_structure.json")\n    except Exception:\n        pass\n    try:\n        return _read_local(os.path.join(_REAL_LOCAL_DIR, "model_structure.json"))\n    except Exception:\n        return None\n\n# ===== inlined from app.py =====\n\n"""RUNTIME Panel app for the demo groundwater model dashboard.\n\nCompiled to static WASM by \`\`panel convert app.py --to pyodide-worker\`\` (the\nDEPLOY agent does that; this file just runs locally with mock data).\n\nHARD IMPORT RULE (Pyodide-only): numpy, pandas, panel, bokeh, param, json, io,\nbase64, pyodide.http. NEVER flopy/pyemu/MF6, NEVER NetCDF/HDF5/datashader.\n\nIt loads the seven pre-computed CONTRACT files through \`\`load_all\`\`\n(one-line mock<->real seam), implements five views (map with stress-period\ntime-slider; baseflow-vs-threshold; borehole hydrographs; water-budget bars; a\nstatic Model Explorer page driven by the optional \`\`model_structure.json\`\`),\nthe input controls (recharge selector; per-well rate sliders; preset toggles),\nclient-side SUPERPOSITION (\`\`superposition.Superposer\`\`) with the map coherence\nrule, and CSV / PNG / ESRI ASCII-grid exports as client-side downloads.\n"""\n\nimport html\nimport io\n\nimport numpy as np\nimport pandas as pd\nimport panel as pn\nimport param\nfrom bokeh.models import (\n    ColorBar, ColumnDataSource, HoverTool, LinearColorMapper, Span,\n)\nfrom bokeh.palettes import Viridis256\nfrom bokeh.plotting import figure\n\n\n# ============================================================================\n# Design system \u2014 "Hydrological Survey Instrument"\n# Aesthetic: refined editorial-cartographic. Deep teal on warm paper, a single\n# crimson signal accent, IBM Plex Serif display + Plex Sans/Mono. The palette is\n# the single source of truth; CSS strings below mirror these hex values (kept\n# in sync by hand \u2014 CSS is plain, never f-strings, to avoid brace escaping).\n# ============================================================================\n# --- Palette (token values per dashboard/DESIGN_SPEC.md \xa72) ----------------\nACCENT = "#0E7C8B"     # refined teal \u2014 primary / baseflow series / template\nACCENT_DK = "#0A4D57"  # accent-deep \u2014 header gradient, headings, hovers\nSPLASH_BG = "#0f3d4a"  # first-load splash (spec: keep)\nOCHRE = "#9A6A00"      # borehole hydrograph series (teal/ochre \u2014 CVD-safe pair)\nTHRESHOLD = "#C8102E"  # crimson \u2014 ecological threshold (the signal accent)\nPOS_FLUX = "#2f7d92"   # budget: inflow (+) \u2014 teal family\nNEG_FLUX = "#C8102E"   # budget: outflow (-) \u2014 crimson family\nSTREAM = "#2b8cbe"     # stream overlay on the map\nPRESET_ON = "#d8682b"  # candidate well, toggled ON (warm signal)\nPAPER = "#F7F4EE"      # warm paper \u2014 plot/page background (kills clinical look)\nINK = "#10242B"        # primary text (deep teal-black, ~13:1 on paper)\nMUTED = "#5b6b73"      # captions / secondary text\nHAIRLINE = "#E3DDD2"   # hairline gridlines / rules on paper\nAXIS_LINE = "#C9C1B4"  # thin axis lines / major ticks\n# CONVENTION: prior/baseline reference = grey; posterior/scenario change = blue.\n# Applied to the timeseries series (band + central line + markers).\nPRIOR = "#a9a293"      # prior / baseline reference \u2014 neutral grey\nCHANGE = "#2166AC"     # posterior / scenario change \u2014 blue (CVD-safe vs crimson)\n# CVD-safe diverging ramp for the drawdown map: deep ochre (head lowered) ->\n# paper -> deep teal (head raised). Replaces RdBu (red/blue fails deuteranopia).\nDD_DIVERGING = ["#6E4B00", "#9A6A00", "#C68A1E", "#D9B05B", "#E8D5A8",\n                "#F7F4EE",\n                "#D6E5E3", "#9BC8CE", "#4FA3AE", "#0E7C8B", "#0A4D57"]\n\n# --- Fonts -----------------------------------------------------------------\nFONT_BODY = "IBM Plex Sans"\nFONT_DISPLAY = "IBM Plex Serif"\nFONT_MONO = "IBM Plex Mono"\nFONT_URL = ("https://fonts.googleapis.com/css2?"\n            "family=IBM+Plex+Serif:wght@400;500;600;700"\n            "&family=IBM+Plex+Mono:wght@400;500"\n            "&family=IBM+Plex+Sans:wght@300;400;500;600&display=swap")\n\n# --- Global CSS (plain string; mirrors palette/fonts above) ----------------\n# Inline pane styles + per-figure Bokeh theming carry the identity reliably;\n# this layer sets typography and the warm-paper backdrop page-wide.\nAPP_CSS = """\n:root { --paper:#F7F4EE; --ink:#10242B; --muted:#5b6b73; --line:#E3DDD2;\n        --teal:#0E7C8B; --teal-dk:#0A4D57; }\nbody, .bk-root, .markdown, .bk-panel-models-markup-HTML {\n  font-family:'IBM Plex Sans', system-ui, -apple-system, sans-serif;\n  color:#10242B; }\nh1,h2,h3,h4,h5,\n.markdown h1,.markdown h2,.markdown h3,.markdown h4,\n.bk-root h1,.bk-root h2,.bk-root h3,.bk-root h4 {\n  font-family:'IBM Plex Serif','Iowan Old Style',Georgia,serif;\n  font-weight:600; letter-spacing:-0.012em; color:#0A4D57; }\n.bk-root .bk-tab { font-family:'IBM Plex Sans',sans-serif; font-weight:500;\n  letter-spacing:.01em; }\n/* warm paper backdrop for the main scroll area */\n.pn-wrapper, #main, .main, .bk.bk-Column { background-color:transparent; }\n/* one orchestrated load reveal: staggered 6px rise + fade for the main panels */\n@keyframes viewRise { from { opacity:0; transform:translateY(6px); }\n                      to   { opacity:1; transform:translateY(0); } }\n.view-reveal { animation: viewRise .5s cubic-bezier(.2,.7,.3,1) both; }\n.view-reveal.d1 { animation-delay:.05s; }\n.view-reveal.d2 { animation-delay:.13s; }\n.view-reveal.d3 { animation-delay:.21s; }\n"""\n\npn.extension(sizing_mode="stretch_width", notifications=True, raw_css=[APP_CSS])\n\n# ============================================================================\n# Load contract data (through the single seam)\n# ============================================================================\n_DATA = load_all()\nMETA = _DATA["meta.json"]\nGRID = _DATA["grid.json"]\nBASELINE = _DATA["baseline_heads.json"]\nBASEFLOW = _DATA["baseflow.json"]\nHYDRO = _DATA["hydrographs.json"]\nBUDGET = _DATA["budget.json"]\nUNIT = _DATA["unit_response.json"]\n\nSUP = Superposer(META, GRID, BASELINE, BASEFLOW, HYDRO, UNIT)\n\n# Optional Model-Explorer payload (not part of the seven-file CONTRACT). None if\n# the offline build_model_explorer.py step has not been run -> page degrades.\nMODEL_STRUCT = load_model_structure()\n\n# Selectable plan-view parameters for the Model Explorer (k, sy, ss, top).\nEXPLORER_FIELDS = (MODEL_STRUCT or {}).get("fields_meta", [])\nFIELD_BY_KEY = {f["key"]: f for f in EXPLORER_FIELDS}\nFIELD_KEYS = [f["key"] for f in EXPLORER_FIELDS] or ["k"]\nEXPLORER_NODATA = -9999.0   # sentinel used in grid_fields for inactive cells\n\n# Packages that carry raw MF6 input text (clickable in the Explorer sidebar).\nEXPLORER_PKGS = [p for p in (MODEL_STRUCT or {}).get("packages", []) if p.get("text")]\nPKG_BY_CODE = {p["code"]: p for p in EXPLORER_PKGS}\nPKG_CODES = [p["code"] for p in EXPLORER_PKGS]\n\nNPER = META["stress_periods"]["nper"]\nNRLEV = META["recharge_levels"]["nrlev"]\nSP_LABELS = META["stress_periods"]["labels"]\nRL_LABELS = META["recharge_levels"]["labels"]\nRL_MULT = META["recharge_levels"]["multipliers"]\nRL_BASE = META["recharge_levels"]["baseline_index"]\nTIMES = META["stress_periods"]["times_d"]\nHEAD_RANGE = META.get("head_color_range", None)\nECO = float(META["eco_threshold_m3d"])\nX0, Y0, DW, DH = GRID["x0"], GRID["y0"], GRID["dw"], GRID["dh"]\nNROW, NCOL = GRID["nrow"], GRID["ncol"]\nCELL = META["grid"]["delr_m"]\n\nBOREHOLE_IDS = list(HYDRO["boreholes"].keys())\nEXISTING = GRID["wells_existing"]\nPRESETS = GRID["wells_preset"]\nBUDGET_TERMS = BUDGET["terms"]\n\n\n# ============================================================================\n# Controls (param-driven state)\n# ============================================================================\nclass State(param.Parameterized):\n    recharge = param.Integer(default=RL_BASE, bounds=(0, NRLEV - 1))\n    stress_period = param.Integer(default=0, bounds=(0, NPER - 1))\n    map_mode = param.Selector(default="Head", objects=["Head", "Drawdown vs baseline"])\n    borehole = param.Selector(default=BOREHOLE_IDS[0], objects=BOREHOLE_IDS)\n    explorer_field = param.Selector(default=FIELD_KEYS[0], objects=FIELD_KEYS)\n\n\nSTATE = State()\n\n# recharge selector \u2014 the labelled values say what it is\nrecharge_sel = pn.widgets.DiscreteSlider(\n    name="Recharge",\n    options={lab: i for lab, i in zip(RL_LABELS, range(NRLEV))},\n    value=RL_BASE,\n)\nrecharge_sel.link(STATE, value="recharge")\n\n# Time (stress period) is a single-snapshot control \u2014 it lives in the two views\n# that show one period: the Map and the Budget. Two sliders, one shared state,\n# kept in sync so changing either updates both. (Month labels imply "time".)\ndef _make_sp_slider():\n    sl = pn.widgets.DiscreteSlider(\n        name="", options={lab: i for lab, i in zip(SP_LABELS, range(NPER))}, value=0)\n    sl.link(STATE, value="stress_period")\n    return sl\n\n\nsp_slider = _make_sp_slider()          # Map tab\nsp_slider_budget = _make_sp_slider()   # Budget tab\n\n\ndef _sync_sp(event):\n    if sp_slider.value != event.new:\n        sp_slider.value = event.new\n    if sp_slider_budget.value != event.new:\n        sp_slider_budget.value = event.new\n\n\nSTATE.param.watch(_sync_sp, "stress_period")\n\nmap_mode_sel = pn.widgets.RadioButtonGroup(\n    options=["Head", "Drawdown vs baseline"], value="Head",\n)\nmap_mode_sel.link(STATE, value="map_mode")\n\nbh_sel = pn.widgets.Select(name="Borehole", options=BOREHOLE_IDS, value=BOREHOLE_IDS[0])\nbh_sel.link(STATE, value="borehole")\n\n# --- Model Explorer controls (independent of the scenario levers) -----------\n# Parameter selector (recolours the plan-view map) + boundary-condition toggles.\nfield_sel = pn.widgets.Select(\n    name="Parameter",\n    options=({f["label"]: f["key"] for f in EXPLORER_FIELDS} or {"K": "k"}),\n    value=FIELD_KEYS[0],\n)\nfield_sel.link(STATE, value="explorer_field")\n\nbc_wel = pn.widgets.Checkbox(name="Wells (WEL)", value=True)\nbc_ghb = pn.widgets.Checkbox(name="General-head (GHB)", value=True)\nbc_sfr = pn.widgets.Checkbox(name="Stream (SFR)", value=True)\nbc_obs = pn.widgets.Checkbox(name="Observation points", value=False)\nBC_TOGGLES = (bc_wel, bc_ghb, bc_sfr, bc_obs)\n\n# Package picker \u2014 click a package code to show its raw MF6 input text.\npkg_sel = (pn.widgets.RadioButtonGroup(\n    options=PKG_CODES, value=PKG_CODES[0], orientation="vertical",\n    button_type="default") if PKG_CODES else None)\n\n# --- Abstraction wells: one uniform control per well ------------------------\n# Each well = on/off flag + rate slider. Existing wells default ON at their\n# calibrated rate; candidate wells default OFF. Labels carry only the short id\n# (units are stated once on the section header). A well switched OFF contributes\n# zero pumping (rate 0) to the superposition.\nwell_toggles = {}\nwell_sliders = {}\nwell_rows = []\n\n\ndef _well_row(key, label, value, lo, candidate):\n    tog = pn.widgets.Checkbox(value=not candidate, width=22, align="center")\n    sl = pn.widgets.FloatSlider(name=label, start=lo, end=0.0, step=5.0,\n                                value=value, format="0", margin=(2, 6, 2, 2))\n    styles = ({"border-left": f"3px solid {ACCENT}", "padding-left": "6px"}\n              if candidate else {})\n    well_toggles[key] = tog\n    well_sliders[key] = sl\n    well_rows.append(pn.Row(tog, sl, sizing_mode="stretch_width",\n                            margin=(0, 0), styles=styles))\n\n\nfor w in EXISTING:\n    _well_row(w["id"], w["id"], float(w["base_rate_m3d"]), -1000.0, candidate=False)\nfor p in PRESETS:\n    _well_row(p["id"], p["name"].replace("Candidate ", ""), -150.0, -300.0,\n              candidate=True)\n\n\ndef current_rates():\n    # existing well OFF -> rate 0 (well shut in); ON -> slider rate\n    existing_rates = {\n        w["id"]: (float(well_sliders[w["id"]].value)\n                  if well_toggles[w["id"]].value else 0.0)\n        for w in EXISTING\n    }\n    preset_rates = {p["id"]: float(well_sliders[p["id"]].value) for p in PRESETS}\n    preset_on = {p["id"]: bool(well_toggles[p["id"]].value) for p in PRESETS}\n    return existing_rates, preset_rates, preset_on\n\n\n# ============================================================================\n# Shared Bokeh theming \u2014 makes the four views read as one instrument\n# ============================================================================\ndef _style_fig(p):\n    """Apply the survey-instrument look to a Bokeh figure (fonts, paper, rules)."""\n    p.background_fill_color = PAPER\n    p.border_fill_color = "white"\n    p.outline_line_color = None\n    p.min_border_left = 14\n    p.min_border_right = 14\n    # Title \u2014 Plex Serif display, deep teal\n    p.title.text_font = FONT_DISPLAY\n    p.title.text_font_style = "normal"\n    p.title.text_font_size = "13px"\n    p.title.text_color = ACCENT_DK\n    p.title.standoff = 10\n    # Axes \u2014 Plex Sans labels, Plex Mono tick numbers\n    for ax in (p.xaxis, p.yaxis):\n        ax.axis_label_text_font = FONT_BODY\n        ax.axis_label_text_font_style = "normal"\n        ax.axis_label_text_font_size = "11px"\n        ax.axis_label_text_color = MUTED\n        ax.major_label_text_font = FONT_MONO\n        ax.major_label_text_font_size = "9px"\n        ax.major_label_text_color = MUTED\n        ax.axis_line_color = AXIS_LINE\n        ax.major_tick_line_color = AXIS_LINE\n        ax.minor_tick_line_color = None\n    # Grid \u2014 drop verticals; horizontals as low-contrast hairlines (\xa74)\n    p.xgrid.grid_line_color = None\n    p.ygrid.grid_line_color = HAIRLINE\n    p.ygrid.grid_line_alpha = 0.7\n    p.ygrid.minor_grid_line_color = None\n    # Legend \u2014 borderless, light (only if the figure actually has one)\n    if len(p.legend) > 0:\n        p.legend.label_text_font = FONT_BODY\n        p.legend.label_text_font_size = "8pt"\n        p.legend.border_line_color = None\n        p.legend.background_fill_color = "white"\n        p.legend.background_fill_alpha = 0.75\n        p.legend.spacing = 1\n        p.legend.padding = 6\n    return p\n\n\n# ============================================================================\n# Map view\n# ============================================================================\n# Fully transparent fill for inactive-domain (NaN) cells.\n_NAN_TRANSPARENT = "rgba(0,0,0,0)"\n\n\ndef _head_mapper():\n    if HEAD_RANGE:\n        low, high = HEAD_RANGE\n    else:\n        # nan-aware: inactive cells are NaN and must not drag the colour range.\n        low = float(np.nanmin(SUP.bh_mean))\n        high = float(np.nanmax(SUP.bh_mean))\n    return LinearColorMapper(palette=Viridis256, low=low, high=high,\n                             nan_color=_NAN_TRANSPARENT)\n\n\ndef _dd_mapper(absmax):\n    # CVD-safe diverging: ochre = head lowered (-), teal = head raised (+).\n    return LinearColorMapper(palette=DD_DIVERGING, low=-absmax, high=absmax,\n                             nan_color=_NAN_TRANSPARENT)\n\n\ndef build_map():\n    rl = STATE.recharge\n    sp = STATE.stress_period\n    er, pr, on = current_rates()\n\n    if STATE.map_mode == "Head":\n        arr = SUP.map_central(rl, sp, er, pr, on)\n        mapper = _head_mapper()\n        title = f"Head (m)  \xb7  {RL_LABELS[rl]}  \xb7  {SP_LABELS[sp]}"\n        cbar_title = "head (m)"\n    else:\n        arr = SUP.map_delta(rl, sp, er, pr, on)  # negative = lowered\n        absmax = max(1e-6, float(np.nanmax(np.abs(arr))))\n        mapper = _dd_mapper(absmax)\n        title = f"Head change vs baseline (m)  \xb7  {RL_LABELS[rl]}  \xb7  {SP_LABELS[sp]}"\n        cbar_title = "\u0394head (m)"\n\n    # Bokeh image expects [row][col] with row 0 at the BOTTOM of the y-range.\n    # Our arrays are row 0 = NORTH (top). Flip vertically so north plots up.\n    img = np.flipud(arr)\n\n    # Equal x/y scale: frame sized to the data aspect so a metre east == a metre\n    # north (square cells). DW x DH = 5000 x 10000 -> tall, narrow. The global\n    # pn.extension(sizing_mode="stretch_width") otherwise leaks responsiveness into\n    # the figure and stretches the frame width; pin BOTH the overall width/height\n    # and the frame so the 1:2 aspect is exact and non-responsive. (No match_aspect\n    # \u2014 that would only re-expand the data range to mask a stretched frame.)\n    _fh = 640\n    _fw = int(round(_fh * DW / DH))\n    p = figure(\n        title=title, sizing_mode="fixed",\n        width=_fw + 170, height=_fh + 110,\n        frame_width=_fw, frame_height=_fh,\n        x_range=(X0, X0 + DW), y_range=(Y0, Y0 + DH),\n        x_axis_label="Easting (m)", y_axis_label="Northing (m)",\n        tools="pan,wheel_zoom,reset,save",\n    )\n    p.image(image=[img], x=X0, y=Y0, dw=DW, dh=DH, color_mapper=mapper)\n    cbar = ColorBar(color_mapper=mapper, title=cbar_title)\n    p.add_layout(cbar, "right")\n\n    # stream overlay\n    p.line(GRID["stream"]["x"], GRID["stream"]["y"], line_width=3,\n           color=STREAM, legend_label="Stream")\n\n    # boreholes\n    bx = [b["x"] for b in GRID["boreholes"]]\n    by = [b["y"] for b in GRID["boreholes"]]\n    bid = [b["id"] for b in GRID["boreholes"]]\n    bsrc = ColumnDataSource(dict(x=bx, y=by, id=bid))\n    br = p.scatter("x", "y", source=bsrc, size=8, marker="triangle",\n                   fill_color="white", line_color="black", legend_label="Borehole")\n\n    # existing wells\n    ex = [w["x"] for w in EXISTING]\n    ey = [w["y"] for w in EXISTING]\n    eid = [w["id"] for w in EXISTING]\n    esrc = ColumnDataSource(dict(x=ex, y=ey, id=eid))\n    p.scatter("x", "y", source=esrc, size=11, marker="circle",\n              fill_color="black", line_color="white", legend_label="Existing well")\n\n    # preset wells (highlight ones that are ON)\n    px = [pp["x"] for pp in PRESETS]\n    py = [pp["y"] for pp in PRESETS]\n    pid = [pp["id"] for pp in PRESETS]\n    pon = ["ON" if on.get(pp["id"]) else "off" for pp in PRESETS]\n    pcol = [PRESET_ON if on.get(pp["id"]) else "#bdbdbd" for pp in PRESETS]\n    psrc = ColumnDataSource(dict(x=px, y=py, id=pid, state=pon, color=pcol))\n    p.scatter("x", "y", source=psrc, size=14, marker="square",\n              fill_color="color", line_color="black", legend_label="Candidate well")\n\n    p.add_tools(HoverTool(renderers=[br], tooltips=[("Borehole", "@id")]))\n    _style_fig(p)\n    p.legend.location = "top_right"\n    return p\n\n\n# ============================================================================\n# SW\u2013GW exchange view (stream\u2013aquifer exchange at the TAILWATER reach group)\n# ============================================================================\ndef build_swgw_exchange():\n    rl = STATE.recharge\n    er, pr, on = current_rates()\n    central, p10, p90 = SUP.baseflow_series(rl, er, pr, on)\n    # Baseline reference (calibrated baseline, baseline recharge) WITH its\n    # posterior uncertainty range, so the scenario's deviation is visible\n    # against the baseline spread \u2014 not just the baseline mean.\n    base = SUP.bf["series"][SUP.primary_series]\n    base_mean = np.asarray(base["mean"][RL_BASE], dtype=float)\n    base_p10 = np.asarray(base["p10"][RL_BASE], dtype=float)\n    base_p90 = np.asarray(base["p90"][RL_BASE], dtype=float)\n\n    p = figure(\n        title=f"SW\u2013GW exchange  \xb7  {RL_LABELS[rl]}",\n        height=560, x_axis_label="Time (model days)",\n        y_axis_label="SW\u2013GW exchange (m\xb3/d)",\n        tools="pan,wheel_zoom,reset,save",\n    )\n    src = ColumnDataSource(dict(t=TIMES, mean=central, p10=p10, p90=p90,\n                                label=SP_LABELS))\n    bsrc = ColumnDataSource(dict(t=TIMES, bmean=base_mean, bp10=base_p10, bp90=base_p90))\n    # Baseline P10\u2013P90 band (behind), then the scenario band (tracks the central).\n    p.varea(x="t", y1="bp10", y2="bp90", source=bsrc, fill_alpha=0.12,\n            fill_color=PRIOR, legend_label="Baseline P10\u2013P90")\n    p.varea(x="t", y1="p10", y2="p90", source=src, fill_alpha=0.20,\n            fill_color=CHANGE, legend_label="Scenario P10\u2013P90")\n    p.line("t", "bmean", source=bsrc, line_width=1.5, color=PRIOR,\n           line_dash="dashed", legend_label="Baseline mean")\n    line = p.line("t", "mean", source=src, line_width=2.5, color=CHANGE,\n                  legend_label="Central forecast")\n    p.scatter("t", "mean", source=src, size=4, color=CHANGE)\n\n    thr = Span(location=ECO, dimension="width", line_color=THRESHOLD,\n               line_dash="dashed", line_width=2)\n    p.add_layout(thr)\n    # legend proxy for threshold\n    p.line([TIMES[0], TIMES[-1]], [ECO, ECO], color=THRESHOLD, line_dash="dashed",\n           line_width=2, legend_label="Eco threshold")\n\n    p.add_tools(HoverTool(renderers=[line], tooltips=[\n        ("Period", "@label"), ("SW\u2013GW exchange", "@mean{0,0} m3/d"),\n        ("P10", "@p10{0,0}"), ("P90", "@p90{0,0}")]))\n    _style_fig(p)\n    p.legend.location = "bottom_left"\n    return p\n\n\n# ============================================================================\n# Hydrograph view\n# ============================================================================\ndef build_hydrograph():\n    rl = STATE.recharge\n    bid = STATE.borehole\n    er, pr, on = current_rates()\n    central, p10, p90 = SUP.hydrograph_series(rl, bid, er, pr, on)\n\n    p = figure(\n        title=f"Borehole {bid}  \xb7  {RL_LABELS[rl]}",\n        height=560, x_axis_label="Time (model days)", y_axis_label="Head (m)",\n        tools="pan,wheel_zoom,reset,save",\n    )\n    # Baseline reference (calibrated baseline, baseline recharge) WITH its\n    # posterior uncertainty range \u2014 not just the baseline mean.\n    b = SUP.hydro["boreholes"][bid]\n    base_mean = np.asarray(b["mean"][RL_BASE], dtype=float)\n    base_p10 = np.asarray(b["p10"][RL_BASE], dtype=float)\n    base_p90 = np.asarray(b["p90"][RL_BASE], dtype=float)\n\n    src = ColumnDataSource(dict(t=TIMES, mean=central, p10=p10, p90=p90,\n                                label=SP_LABELS))\n    bsrc = ColumnDataSource(dict(t=TIMES, bmean=base_mean, bp10=base_p10, bp90=base_p90))\n    # Baseline P10\u2013P90 band (behind), then scenario band (tracks the central).\n    p.varea(x="t", y1="bp10", y2="bp90", source=bsrc, fill_alpha=0.12,\n            fill_color=PRIOR, legend_label="Baseline P10\u2013P90")\n    p.varea(x="t", y1="p10", y2="p90", source=src, fill_alpha=0.20,\n            fill_color=CHANGE, legend_label="Scenario P10\u2013P90")\n    p.line("t", "bmean", source=bsrc, line_width=1.5, color=PRIOR,\n           line_dash="dashed", legend_label="Baseline mean")\n    line = p.line("t", "mean", source=src, line_width=2.5, color=CHANGE,\n                  legend_label="Central forecast")\n    p.scatter("t", "mean", source=src, size=4, color=CHANGE)\n    p.add_tools(HoverTool(renderers=[line], tooltips=[\n        ("Period", "@label"), ("Head", "@mean{0,0.00} m"),\n        ("P10", "@p10{0,0.00}"), ("P90", "@p90{0,0.00}")]))\n    _style_fig(p)\n    p.legend.location = "top_right"\n    return p\n\n\n# ============================================================================\n# Budget view\n# ============================================================================\ndef build_budget():\n    rl = STATE.recharge\n    sp = STATE.stress_period\n    er, _, _ = current_rates()\n    # baseline WEL term + user delta on existing wells (preset add handled too)\n    user_delta = sum(er[w["id"]] - float(w["base_rate_m3d"]) for w in EXISTING)\n    _, pr, on = current_rates()\n    preset_add = sum(pr[p["id"]] for p in PRESETS if on.get(p["id"]))\n\n    terms = BUDGET_TERMS\n    vals = []\n    for t in terms:\n        v = float(BUDGET["mean"][t][rl][sp])\n        if t == "WEL":\n            v = v + user_delta + preset_add\n        vals.append(v)\n    p10 = [float(BUDGET["p10"][t][rl][sp]) for t in terms]\n    p90 = [float(BUDGET["p90"][t][rl][sp]) for t in terms]\n\n    colors = [POS_FLUX if v >= 0 else NEG_FLUX for v in vals]\n    src = ColumnDataSource(dict(term=terms, val=vals, p10=p10, p90=p90, color=colors))\n    p = figure(\n        title=f"Water budget (m3/d)  \xb7  {RL_LABELS[rl]}  \xb7  {SP_LABELS[sp]}",\n        x_range=terms, height=560, y_axis_label="Flux (m3/d, in + / out -)",\n        tools="save",\n    )\n    bars = p.vbar(x="term", top="val", width=0.7, source=src, fill_color="color",\n                  line_color="black")\n    p.add_tools(HoverTool(renderers=[bars], tooltips=[\n        ("Term", "@term"), ("Flux", "@val{0,0} m3/d"),\n        ("P10", "@p10{0,0}"), ("P90", "@p90{0,0}")]))\n    zero = Span(location=0, dimension="width", line_color=INK, line_width=1)\n    p.add_layout(zero)\n    _style_fig(p)\n    return p\n\n\n# ============================================================================\n# Model Explorer \u2014 interactive 2D plan-view: recolour by selected parameter\n# (K / Sy / Ss / elevation) and toggle boundary-condition overlays on/off.\n# Independent of the scenario levers; driven by STATE.explorer_field + toggles.\n# ============================================================================\ndef build_explorer_map():\n    if not MODEL_STRUCT:\n        return None\n    key = STATE.explorer_field\n    fmeta = FIELD_BY_KEY.get(key, {"label": key, "units": "", "range": None})\n    arr = np.array(MODEL_STRUCT["grid_fields"][key], dtype=float)\n    arr = np.where(arr == EXPLORER_NODATA, np.nan, arr)   # inactive -> transparent\n\n    rng = fmeta.get("range")\n    if rng and rng[0] != rng[1]:\n        lo, hi = float(rng[0]), float(rng[1])\n    else:\n        # Flat field (e.g. Ss is uniform here) \u2014 pad so the colour bar isn't degenerate.\n        v = float(np.nanmean(arr)) if np.isfinite(arr).any() else 0.0\n        pad = abs(v) * 0.05 or 1.0\n        lo, hi = v - pad, v + pad\n    mapper = LinearColorMapper(palette=Viridis256, low=lo, high=hi,\n                               nan_color=_NAN_TRANSPARENT)\n\n    # row 0 = NORTH; flip so north plots up (matches the scenario map).\n    img = np.flipud(arr)\n    units = fmeta.get("units", "")\n    unit_suffix = f"  ({units})" if units and units != "\u2013" else ""\n\n    # Equal x/y scale via a pinned frame AND overall size (see build_map: the\n    # global stretch_width default would otherwise stretch the frame width).\n    _fh = 600\n    _fw = int(round(_fh * DW / DH))\n    p = figure(\n        title=f"{fmeta['label']}{unit_suffix}", sizing_mode="fixed",\n        width=_fw + 170, height=_fh + 110,\n        frame_width=_fw, frame_height=_fh,\n        x_range=(X0, X0 + DW), y_range=(Y0, Y0 + DH),\n        x_axis_label="Easting (m)", y_axis_label="Northing (m)",\n        tools="pan,wheel_zoom,reset,save",\n    )\n    p.image(image=[img], x=X0, y=Y0, dw=DW, dh=DH, color_mapper=mapper)\n    p.add_layout(ColorBar(color_mapper=mapper, title=(units or "")), "right")\n\n    bcs = MODEL_STRUCT["bcs"]\n    if bc_sfr.value:\n        p.line(GRID["stream"]["x"], GRID["stream"]["y"], line_width=3,\n               color=STREAM, legend_label="Stream (SFR)")\n    if bc_ghb.value and bcs.get("GHB", {}).get("cells"):\n        c = bcs["GHB"]["cells"]\n        p.scatter([d["x"] for d in c], [d["y"] for d in c], size=11, marker="square",\n                  fill_color="#E69F00", line_color="black", legend_label="General-head (GHB)")\n    if bc_wel.value and bcs.get("WEL", {}).get("cells"):\n        c = bcs["WEL"]["cells"]\n        p.scatter([d["x"] for d in c], [d["y"] for d in c], size=12, marker="circle",\n                  fill_color=INK, line_color="white", legend_label="Wells (WEL)")\n    if bc_obs.value and MODEL_STRUCT["observations"]["head"]:\n        o = MODEL_STRUCT["observations"]["head"]\n        p.scatter([d["x"] for d in o], [d["y"] for d in o], size=9, marker="triangle",\n                  fill_color="white", line_color="black", legend_label="Obs point")\n\n    _style_fig(p)\n    if len(p.legend) > 0:\n        p.legend.location = "top_right"\n    return p\n\n\n# ============================================================================\n# Model Explorer \u2014 STATIC "what is this model?" detail cards (grid, time,\n# packages, boundary conditions, properties, observations). Built once.\n# ============================================================================\ndef _card(title, body_html):\n    """A bordered paper card with a serif heading \u2014 matches the view panel."""\n    return (\n        f"<div style=\\"background:#fff;border:1px solid {HAIRLINE};"\n        f"border-radius:10px;padding:14px 18px;margin:0 0 14px;"\n        f"box-shadow:0 1px 3px rgba(10,77,87,.05);\\">"\n        f"<h3 style=\\"margin:0 0 10px;font-family:'IBM Plex Serif',Georgia,serif;"\n        f"font-size:15px;color:{ACCENT_DK};\\">{title}</h3>{body_html}</div>"\n    )\n\n\ndef _kv_rows(pairs):\n    """Definition-list of (label, value) pairs -> compact two-column HTML."""\n    cells = "".join(\n        f"<tr><td style=\\"padding:3px 16px 3px 0;color:{MUTED};white-space:nowrap;\\">{k}</td>"\n        f"<td style=\\"padding:3px 0;color:{INK};font-family:'IBM Plex Mono',monospace;\\">{v}</td></tr>"\n        for k, v in pairs\n    )\n    return f"<table style=\\"border-collapse:collapse;font-size:12px;\\">{cells}</table>"\n\n\ndef build_structure_cards():\n    """Return a list of HTML panes: [intro, grid+time, packages, BCs, props+obs].\n    The interactive map is composed separately (in the layout section)."""\n    s = MODEL_STRUCT\n    if not s:\n        return [pn.pane.Markdown(\n            "**Model structure is unavailable.** Run the offline "\n            "\`precompute/build_model_explorer.py\` step to generate "\n            "\`model_structure.json\`.",\n            styles={"color": MUTED, "padding": "20px"})]\n\n    mdl, grid, tdis = s["model"], s["grid"], s["tdis"]\n    props, obs = s["properties"], s["observations"]\n\n    # --- intro ---\n    intro = _card(\n        f"{mdl['name']} \u2014 {mdl['type']}",\n        f"<p style=\\"font-size:12.5px;line-height:1.55;color:{INK};margin:0;\\">"\n        f"{mdl['note']}</p>"\n        f"<p style=\\"font-size:11px;color:{MUTED};margin:8px 0 0;\\">"\n        f"Units: length in {mdl['units']['length']}, time in {mdl['units']['time']}.</p>")\n\n    # --- grid ---\n    ext = grid["extent"]\n    grid_card = _card("Grid (DIS)", _kv_rows([\n        ("Layers \xd7 rows \xd7 cols", f"{grid['nlay']} \xd7 {grid['nrow']} \xd7 {grid['ncol']}"),\n        ("Cell size", f"{grid['delr_m']:g} \xd7 {grid['delc_m']:g} m"),\n        ("Extent", f"{ext['xll']:g}\u2013{ext['xur']:g} E, {ext['yll']:g}\u2013{ext['yur']:g} N (m)"),\n        ("Active cells", f"{grid['n_active']:,}  ({grid['n_inactive']:,} inactive)"),\n        ("Ground elevation", f"{grid['top_m'][0]:g} \u2013 {grid['top_m'][1]:g} m"),\n        ("Aquifer base", f"{grid['botm_m'][0]:g} \u2013 {grid['botm_m'][1]:g} m"),\n    ]))\n\n    # --- time ---\n    time_card = _card("Time (TDIS)", _kv_rows([\n        ("Stress periods", f"{tdis['nper']}"),\n        ("Total simulated", f"{tdis['total_time_d']:,g} {tdis['time_units']}"),\n    ]) + f"<p style=\\"font-size:11px;color:{MUTED};margin:10px 0 0;line-height:1.5;\\">"\n        f"{tdis['spinup_note']}</p>")\n\n    # --- boundary conditions ---\n    bc_rows = []\n    for code in ["WEL", "GHB", "RCH", "SFR"]:\n        bc = s["bcs"].get(code)\n        if not bc:\n            continue\n        bc_rows.append(\n            f"<tr>"\n            f"<td style=\\"padding:6px 14px 6px 0;font-family:'IBM Plex Mono',monospace;"\n            f"font-size:11px;font-weight:600;color:{ACCENT_DK};vertical-align:top;\\">{code}</td>"\n            f"<td style=\\"padding:6px 14px 6px 0;font-size:12px;color:{INK};"\n            f"vertical-align:top;white-space:nowrap;\\">{bc['label']}</td>"\n            f"<td style=\\"padding:6px 0;font-size:11.5px;color:{MUTED};line-height:1.45;\\">"\n            f"{bc['summary']}</td></tr>")\n    bc_card = _card(\n        "Boundary conditions",\n        f"<table style=\\"border-collapse:collapse;width:100%;\\">{''.join(bc_rows)}</table>")\n\n    # --- properties + observations (side by side) ---\n    k = props["npf_k"]\n    prop_card = _card("Aquifer properties", _kv_rows([\n        ("Hydraulic conductivity K", f"{k['min']:g} \u2013 {k['max']:g} {k['units']}"),\n        ("Specific yield Sy", f"{props['sto_sy']['min']:g} \u2013 {props['sto_sy']['max']:g}"),\n        ("Specific storage Ss", f"{props['sto_ss']['min']:g} \u2013 {props['sto_ss']['max']:g}"),\n    ]))\n    obs_card = _card("Observations (monitoring)", _kv_rows([\n        ("Head monitoring points", f"{obs['head_count']}"),\n        ("Streamflow gauges", f"{obs['sfr_count']}"),\n    ]) + f"<p style=\\"font-size:11px;color:{MUTED};margin:10px 0 0;line-height:1.5;\\">"\n        f"Locations where simulated heads / flows are recorded and compared against "\n        f"field measurements during history matching.</p>")\n\n    return [\n        pn.pane.HTML(intro, sizing_mode="stretch_width"),\n        pn.Row(\n            pn.pane.HTML(grid_card, sizing_mode="stretch_width"),\n            pn.pane.HTML(time_card, sizing_mode="stretch_width"),\n            sizing_mode="stretch_width"),\n        pn.pane.HTML(bc_card, sizing_mode="stretch_width"),\n        pn.Row(\n            pn.pane.HTML(prop_card, sizing_mode="stretch_width"),\n            pn.pane.HTML(obs_card, sizing_mode="stretch_width"),\n            sizing_mode="stretch_width"),\n    ]\n\n\ndef build_pkg_text_html(code):\n    """Card showing the raw MF6 input-file text for the selected package."""\n    p = PKG_BY_CODE.get(code)\n    if not p:\n        return (f"<div style=\\"background:#fff;border:1px solid {HAIRLINE};"\n                f"border-radius:10px;padding:14px 18px;margin:0 0 14px;color:{MUTED};"\n                f"font-size:12px;\\">Select a package in the sidebar to view its raw "\n                f"MODFLOW&nbsp;6 input file.</div>")\n    body = html.escape(p.get("text", ""))\n    return (\n        f"<div style=\\"background:#fff;border:1px solid {HAIRLINE};border-radius:10px;"\n        f"padding:14px 18px;margin:0 0 14px;box-shadow:0 1px 3px rgba(10,77,87,.05);\\">"\n        f"<h3 style=\\"margin:0 0 2px;font-family:'IBM Plex Serif',Georgia,serif;"\n        f"font-size:15px;color:{ACCENT_DK};\\">{p['code']} \u2014 {p['name']}</h3>"\n        f"<p style=\\"font-size:11px;color:{MUTED};margin:0 0 8px;line-height:1.45;\\">"\n        f"<span style=\\"font-family:'IBM Plex Mono',monospace;color:{INK};\\">"\n        f"{p.get('filename','')}</span> \xb7 {p.get('description','')}</p>"\n        f"<pre style=\\"max-height:460px;overflow:auto;margin:0;padding:12px 14px;"\n        f"background:#0d1f24;color:#cfe3e1;border-radius:8px;"\n        f"font-family:'IBM Plex Mono',monospace;font-size:11px;line-height:1.45;"\n        f"white-space:pre;\\">{body}</pre></div>"\n    )\n\n\n# ============================================================================\n# Reactive panes \u2014 rebuild on any relevant change\n# ============================================================================\n# Map pane is FIXED so the figure's frame_width/frame_height (set to the data\n# aspect) are honoured \u2014 otherwise the global stretch_width distorts x vs y scale.\nmap_pane = pn.pane.Bokeh(sizing_mode="fixed")\nbaseflow_pane = pn.pane.Bokeh()\nhydro_pane = pn.pane.Bokeh()\nbudget_pane = pn.pane.Bokeh()\nexplorer_map_pane = pn.pane.Bokeh(sizing_mode="fixed")   # Model Explorer plan-view\npkg_text_pane = pn.pane.HTML(sizing_mode="stretch_width")  # raw package input text\n\n\ndef refresh_map(*_):\n    map_pane.object = build_map()\n\n\ndef refresh_baseflow(*_):\n    baseflow_pane.object = build_swgw_exchange()\n\n\ndef refresh_hydro(*_):\n    hydro_pane.object = build_hydrograph()\n\n\ndef refresh_budget(*_):\n    budget_pane.object = build_budget()\n\n\ndef refresh_explorer_map(*_):\n    explorer_map_pane.object = build_explorer_map()\n\n\ndef refresh_pkg_text(*_):\n    code = pkg_sel.value if pkg_sel is not None else None\n    pkg_text_pane.object = build_pkg_text_html(code)\n\n\ndef refresh_all(*_):\n    refresh_map()\n    refresh_baseflow()\n    refresh_hydro()\n    refresh_budget()\n\n\n# Wire watchers. State drives view selection; control widgets drive superposition.\nSTATE.param.watch(refresh_map, ["recharge", "stress_period", "map_mode"])\nSTATE.param.watch(refresh_baseflow, ["recharge"])\nSTATE.param.watch(refresh_hydro, ["recharge", "borehole"])\nSTATE.param.watch(refresh_budget, ["recharge", "stress_period"])\n\nfor sl in well_sliders.values():\n    sl.param.watch(refresh_all, "value")\nfor t in well_toggles.values():\n    t.param.watch(refresh_all, "value")\n\n# Explorer map reacts to the parameter selector + BC toggles (scenario-independent).\nSTATE.param.watch(refresh_explorer_map, ["explorer_field"])\nfor _chk in BC_TOGGLES:\n    _chk.param.watch(refresh_explorer_map, "value")\n\n# Package text reacts to the package picker.\nif pkg_sel is not None:\n    pkg_sel.param.watch(refresh_pkg_text, "value")\n\nrefresh_all()\nrefresh_explorer_map()\nrefresh_pkg_text()\n\n\n# ============================================================================\n# Exports (pure-Python buffers -> FileDownload, client-side)\n# ============================================================================\ndef _esri_ascii(arr2d) -> str:\n    """ESRI ASCII grid string of a [row][col] array, row 0 = NORTH."""\n    lines = [\n        f"ncols {NCOL}",\n        f"nrows {NROW}",\n        f"xllcorner {X0}",\n        f"yllcorner {Y0}",\n        f"cellsize {CELL}",\n        "NODATA_value -9999",\n    ]\n    # Inactive cells are NaN in the runtime arrays; re-stamp the NODATA sentinel\n    # so the written header (NODATA_value -9999) is truthful for GIS import.\n    def _fmt(v):\n        return "-9999" if (v is None or v != v) else f"{v:.4f}"\n    for r in range(NROW):\n        lines.append(" ".join(_fmt(arr2d[r][c]) for c in range(NCOL)))\n    return "\\n".join(lines) + "\\n"\n\n\ndef export_map_asc():\n    rl, sp = STATE.recharge, STATE.stress_period\n    er, pr, on = current_rates()\n    if STATE.map_mode == "Head":\n        arr = SUP.map_central(rl, sp, er, pr, on)\n    else:\n        arr = SUP.map_delta(rl, sp, er, pr, on)\n    return io.BytesIO(_esri_ascii(arr).encode())\n\n\ndef _asc_name():\n    layer = "head" if STATE.map_mode == "Head" else "ddvbaseline"\n    return f"map_{layer}_rl{STATE.recharge}_sp{STATE.stress_period}.asc"\n\n\ndef export_baseflow_csv():\n    rl = STATE.recharge\n    er, pr, on = current_rates()\n    central, p10, p90 = SUP.baseflow_series(rl, er, pr, on)\n    base = SUP.bf["series"][SUP.primary_series]\n    df = pd.DataFrame({\n        "time_d": TIMES, "label": SP_LABELS,\n        "swgw_exchange_m3d": central, "p10": p10, "p90": p90,\n        "baseline_m3d": np.asarray(base["mean"][RL_BASE], dtype=float),\n        "baseline_p10": np.asarray(base["p10"][RL_BASE], dtype=float),\n        "baseline_p90": np.asarray(base["p90"][RL_BASE], dtype=float),\n        "threshold_m3d": ECO,\n    })\n    return io.BytesIO(df.to_csv(index=False).encode())\n\n\ndef export_hydro_csv():\n    rl, bid = STATE.recharge, STATE.borehole\n    er, pr, on = current_rates()\n    central, p10, p90 = SUP.hydrograph_series(rl, bid, er, pr, on)\n    df = pd.DataFrame({\n        "time_d": TIMES, "label": SP_LABELS,\n        f"head_m_{bid}": central, "p10": p10, "p90": p90,\n    })\n    return io.BytesIO(df.to_csv(index=False).encode())\n\n\ndef export_budget_csv():\n    rl, sp = STATE.recharge, STATE.stress_period\n    er, pr, on = current_rates()\n    user_delta = sum(er[w["id"]] - float(w["base_rate_m3d"]) for w in EXISTING)\n    preset_add = sum(pr[p["id"]] for p in PRESETS if on.get(p["id"]))\n    rows = []\n    for t in BUDGET_TERMS:\n        v = float(BUDGET["mean"][t][rl][sp])\n        if t == "WEL":\n            v += user_delta + preset_add\n        rows.append({"term": t, "flux_m3d": v,\n                     "p10": float(BUDGET["p10"][t][rl][sp]),\n                     "p90": float(BUDGET["p90"][t][rl][sp])})\n    return io.BytesIO(pd.DataFrame(rows).to_csv(index=False).encode())\n\n\ndl_map_asc = pn.widgets.FileDownload(\n    callback=export_map_asc, filename="map.asc", label="Map -> ESRI ASCII grid (.asc)",\n    button_type="primary",\n)\n# keep filename in sync with current view\nSTATE.param.watch(lambda *_: setattr(dl_map_asc, "filename", _asc_name()),\n                  ["recharge", "stress_period", "map_mode"])\ndl_map_asc.filename = _asc_name()\n\ndl_bf_csv = pn.widgets.FileDownload(\n    callback=export_baseflow_csv, filename="swgw_exchange.csv",\n    label="SW\u2013GW exchange -> CSV")\ndl_hy_csv = pn.widgets.FileDownload(\n    callback=export_hydro_csv, filename="hydrograph.csv", label="Hydrograph -> CSV")\ndl_bg_csv = pn.widgets.FileDownload(\n    callback=export_budget_csv, filename="budget.csv", label="Budget -> CSV")\n\npng_note = pn.pane.Markdown(\n    "*PNG \u2014 use the save (disk) icon on any plot toolbar.*",\n    styles={"font-size": "11px", "color": MUTED})\n\n\n# ============================================================================\n# Reset\n# ============================================================================\ndef reset_inputs(*_):\n    recharge_sel.value = RL_BASE\n    sp_slider.value = 0\n    for w in EXISTING:\n        well_toggles[w["id"]].value = True\n        well_sliders[w["id"]].value = float(w["base_rate_m3d"])\n    for p in PRESETS:\n        well_toggles[p["id"]].value = False\n        well_sliders[p["id"]].value = -150.0\n\n\nreset_btn = pn.widgets.Button(name="Reset to baseline", button_type="default")\nreset_btn.on_click(reset_inputs)\n\n\n# ============================================================================\n# Layout\n# ============================================================================\ndef _section(title):\n    """Small uppercase rail header \u2014 quiet, lets the controls breathe."""\n    return pn.pane.Markdown(\n        f"<span style='font-family:\\"IBM Plex Mono\\",monospace;font-size:10px;"\n        f"letter-spacing:.18em;text-transform:uppercase;color:{ACCENT};'>{title}</span>",\n        margin=(10, 0, 2, 0))\n\n\ndef _sublabel(text):\n    return pn.pane.Markdown(\n        f"<span style='font-size:11px;font-weight:600;letter-spacing:.02em;"\n        f"color:{ACCENT_DK}'>{text}</span>", margin=(8, 0, 0, 0))\n\n\n# Scenario-page sidebar = global scenario levers (recharge + wells).\ncontrols = pn.Column(\n    _section("Scenario"),\n    recharge_sel,\n    _sublabel("Abstraction wells (m3/d) \u2014 tick = on"),\n    *well_rows,\n    reset_btn,\n    width=320,\n)\n\n# Model-Explorer-page sidebar = parameter selector, BC toggles, package picker.\nexplorer_controls = pn.Column(\n    _section("Parameter"),\n    field_sel,\n    _section("Boundary conditions"),\n    bc_wel, bc_ghb, bc_sfr,\n    _section("Monitoring"),\n    bc_obs,\n    *([_section("Packages (click to view input file)"), pkg_sel]\n      if pkg_sel is not None else []),\n    width=320,\n)\n\n# The equal-scale map is tall and narrow \u2014 centre it in the wide panel.\nmap_centered = pn.Row(pn.layout.HSpacer(), map_pane, pn.layout.HSpacer())\n\n# --- Scenario page: the four scenario views in one bordered card -----------\n# Each tab carries only the controls + export that belong to it.\nmap_tab = pn.Column(pn.Row(map_mode_sel, sp_slider), map_centered, dl_map_asc)\nbaseflow_tab = pn.Column(baseflow_pane, dl_bf_csv)\nhydro_tab = pn.Column(bh_sel, hydro_pane, dl_hy_csv)\nbudget_tab = pn.Column(sp_slider_budget, budget_pane, dl_bg_csv)\n\nviews = pn.Tabs(\n    ("Map", map_tab),\n    ("SW\u2013GW exchange", baseflow_tab),\n    ("Hydrographs", hydro_tab),\n    ("Budget", budget_tab),\n    dynamic=False,\n)\n\nview_panel = pn.Column(\n    views,\n    css_classes=["view-reveal", "d2"],\n    sizing_mode="stretch_width",\n    styles={\n        "background": "#ffffff",\n        "border": f"1px solid {HAIRLINE}",\n        "border-radius": "10px",\n        "padding": "4px 12px 12px",\n        "box-shadow": "0 1px 3px rgba(10,77,87,.05)",\n        "min-height": "640px",\n    },\n    margin=(2, 8, 6, 8),\n)\n\n# --- Model Explorer page: intro card, interactive plan-view map, detail cards ---\n_structure_cards = build_structure_cards()   # [intro, grid+time, pkg, bc, prop+obs]\n_explorer_map_centered = pn.Row(\n    pn.layout.HSpacer(), explorer_map_pane, pn.layout.HSpacer(),\n    sizing_mode="stretch_width")\n_map_header = pn.pane.HTML(\n    f"<h3 style=\\"margin:0 0 2px;font-family:'IBM Plex Serif',Georgia,serif;"\n    f"font-size:15px;color:{ACCENT_DK};\\">Parameters &amp; boundaries (plan view)</h3>"\n    f"<p style=\\"font-size:11px;color:{MUTED};margin:0 0 6px;line-height:1.5;\\">"\n    f"Pick a parameter on the left to recolour the grid; toggle boundary conditions "\n    f"on or off. Inactive cells are blank. Recharge (RCH) is applied over the whole "\n    f"active area.</p>", sizing_mode="stretch_width")\n_map_block = pn.Column(\n    _map_header, _explorer_map_centered, sizing_mode="stretch_width",\n    styles={\n        "background": "#ffffff", "border": f"1px solid {HAIRLINE}",\n        "border-radius": "10px", "padding": "14px 18px", "margin": "0 0 14px",\n        "box-shadow": "0 1px 3px rgba(10,77,87,.05)",\n    })\nexplorer_panel = pn.Column(\n    _structure_cards[0],           # intro\n    _map_block,                    # interactive map\n    pkg_text_pane,                 # raw input text of the selected package\n    *_structure_cards[1:],         # grid/time, BCs, props/obs\n    css_classes=["view-reveal", "d2"],\n    sizing_mode="stretch_width",\n    margin=(2, 8, 6, 8),\n)\n\n# --- In-app page navigation: swap sidebar controls AND main content ---------\n# (Static single-file app: this is in-app navigation, not separate URLs.)\npage_sel = pn.widgets.RadioButtonGroup(\n    options=["Scenario explorer", "Model explorer"],\n    value="Scenario explorer", button_type="default", margin=(2, 0, 6, 0),\n)\nsidebar_body = pn.Column(controls)\nmain_body = pn.Column(view_panel, sizing_mode="stretch_width")\n\n\ndef _switch_page(*_):\n    if page_sel.value == "Model explorer":\n        sidebar_body.objects = [explorer_controls]\n        main_body.objects = [explorer_panel]\n    else:\n        sidebar_body.objects = [controls]\n        main_body.objects = [view_panel]\n\n\npage_sel.param.watch(_switch_page, "value")\n\n_TITLE = "Groundwater Model Dashboard"\nif META.get("mock"):\n    _TITLE += "  \xb7  MOCK DATA"\n\nFOOTER_HTML = f"""\n<div style="margin-top:6px;padding:12px 18px;border-top:1px solid {HAIRLINE};\n     font-family:'IBM Plex Sans',sans-serif;font-size:11px;line-height:1.5;\n     color:{MUTED};">\n  Synthetic demonstration model \xb7 MODFLOW&nbsp;6 \xb7 history-matched with pestpp-ies\n  \xb7 posterior ensemble n&nbsp;=&nbsp;200.\n</div>\n"""\nfooter = pn.pane.HTML(FOOTER_HTML, sizing_mode="stretch_width", margin=(2, 8, 10, 8))\n\ntemplate = pn.template.FastListTemplate(\n    title=_TITLE,             # single title, in the native app-bar (renders reliably)\n    sidebar=[pn.Column(_section("View"), page_sel, margin=(0, 0, 4, 0)), sidebar_body],\n    main=[main_body, footer],\n    accent_base_color=ACCENT,\n    header_background=ACCENT_DK,\n    header_color="#ffffff",\n    font=FONT_BODY,\n    font_url=FONT_URL,\n    sidebar_width=360,\n    main_max_width="1180px",\n)\n\n\n# No custom loading splash: \`panel convert\` emits its own loader for the WASM\n# build while Pyodide initialises; locally the server renders immediately.\n# (A hand-rolled fixed overlay proved unreliable to dismiss in-browser.)\ntemplate.servable(title="Groundwater Model Dashboard")\n\n\nawait write_doc()`)
    self.postMessage({
      type: 'render',
      docs_json: docs_json,
      render_items: render_items,
      root_ids: root_ids
    })
  } catch(e) {
    const traceback = `${e}`
    const tblines = traceback.split('\n')
    self.postMessage({
      type: 'status',
      msg: tblines[tblines.length-2]
    });
    throw e
  }
}

self.onmessage = async (event) => {
  const msg = event.data
  if (msg.type === 'rendered') {
    self.pyodide.runPythonAsync(`
    from panel.io.state import state
    from panel.io.pyodide import _link_docs_worker

    _link_docs_worker(state.curdoc, sendPatch, setter='js')
    `)
  } else if (msg.type === 'patch') {
    self.pyodide.globals.set('patch', msg.patch)
    self.pyodide.runPythonAsync(`
    from panel.io.pyodide import _convert_json_patch
    state.curdoc.apply_json_patch(_convert_json_patch(patch), setter='js')
    `)
    self.postMessage({type: 'idle'})
  } else if (msg.type === 'location') {
    self.pyodide.globals.set('location', msg.location)
    self.pyodide.runPythonAsync(`
    import json
    from panel.io.state import state
    from panel.util import edit_readonly
    if state.location:
        loc_data = json.loads(location)
        with edit_readonly(state.location):
            state.location.param.update({
                k: v for k, v in loc_data.items() if k in state.location.param
            })
    `)
  }
}

startApplication()